import React, { useState } from 'react';
import axios from 'axios';



function GrowthCell({ value }) {
  if (!value || value === '—' || value === 'N/A') return <td className="neutral">{value || 'N/A'}</td>;
  const isPositive = !value.startsWith('-');
  return <td className={isPositive ? 'positive' : 'negative'}>{isPositive ? '▲ ' : '▼ '}{value}</td>;
}

export default function App() {
  const [symbol, setSymbol] = useState('');
  const [stockData, setStockData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleSearch = async () => {
    if (!symbol.trim()) return;
    setLoading(true);
    setError('');
    setStockData(null);
    try {
      const res = await axios.get(`/api/stock/${symbol.trim().toUpperCase()}`);
      setStockData(res.data);
    } catch (e) {
      setError(e.response?.data?.error || 'Failed to fetch data. Please check the symbol (e.g. TATASTEEL, INFY, RELIANCE)');
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') handleSearch();
  };

  return (
    <>
      <style>{styles}</style>
      <div className="app">

        {/* HEADER */}
        <div className="header">
          <div className="header-tag">Stock Research</div>
          <h1>Analyst <span>Report</span></h1>
          <p>Enter an NSE/BSE symbol to generate a clean 1-pager</p>
        </div>

        {/* SEARCH */}
        <div className="search-box">
          <span className="search-label">Symbol</span>
          <input
            className="search-input"
            type="text"
            placeholder="e.g. TATASTEEL, INFY, RELIANCE, HDFCBANK"
            value={symbol}
            onChange={e => setSymbol(e.target.value)}
            onKeyDown={handleKeyDown}
          />
          <button className="search-btn" onClick={handleSearch} disabled={loading || !symbol.trim()}>
            {loading ? 'Fetching...' : 'Analyze →'}
          </button>
        </div>

        {/* ERROR */}
        {error && <div className="error-box">⚠ {error}</div>}

        {/* LOADING */}
        {loading && (
          <div className="loading">
            <div className="spinner" />
            <p>Fetching data from screener.in...</p>
          </div>
        )}

        {/* REPORT */}
        {stockData && !loading && (
          <>
            {/* Company Header */}
            <div className="company-header">
              <div>
                <div className="company-name">{stockData.companyName || stockData.symbol}</div>
                <div className="company-symbol">NSE: {stockData.symbol}</div>
              </div>
              <div className="cmp-badge">
                <div className="cmp-label">Current Price</div>
                <div className="cmp-value">₹{stockData.cmp || '—'}</div>
              </div>
            </div>

            {/* TABLE 1 — Key Ratios */}
            <div className="section">
              <div className="section-title">Key Metrics</div>
              <div className="stat-cards">
                <div className="stat-card">
                  <div className="stat-label">P/E Ratio</div>
                  <div className="stat-value">{stockData.pe || '—'}</div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">Market Cap</div>
                  <div className="stat-value">{stockData.marketCap ? `₹${stockData.marketCap}` : '—'}</div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">Dividend Yield</div>
                  <div className="stat-value">{stockData.dividendYield || '—'}</div>
                </div>
                <div className="stat-card">
                  <div className="stat-label">Book Value</div>
                  <div className="stat-value">{stockData.bookValue ? `₹${stockData.bookValue}` : '—'}</div>
                </div>
              </div>
            </div>

            {/* TABLE 2 — Financial History */}
            <div className="section">
              <div className="section-title">Financial History (Last 3 Years)</div>
              <div className="table-wrap">
                <table>
                  <thead>
                    <tr>
                      <th>Year</th>
                      <th>Revenue (Cr)</th>
                      <th>Revenue Growth</th>
                      <th>Net Profit (Cr)</th>
                      <th>Profit Growth</th>
                      <th>Net Margin</th>
                    </tr>
                  </thead>
                  <tbody>
                    {stockData.financials && stockData.financials.length > 0 ? (
                      stockData.financials.map((f, i) => (
                        <tr key={i}>
                          <td style={{ fontWeight: 600, color: '#e8eaf0' }}>{f.year}</td>
                          <td>{f.revenue}</td>
                          <GrowthCell value={f.revenueGrowth} />
                          <td>{f.profit}</td>
                          <GrowthCell value={f.profitGrowth} />
                          <td>{f.netProfitMargin}</td>
                        </tr>
                      ))
                    ) : (
                      <tr><td colSpan={6} className="neutral" style={{ textAlign: 'center', padding: '24px' }}>No financial data found</td></tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>

            {/* TABLE 3 — Median PE */}
            <div className="section">
              <div className="section-title">Median P/E Analysis</div>
              <div className="pe-cards">
                <div className="pe-card">
                  <div className="pe-period">1 Year</div>
                  <div className="pe-value">{stockData.medianPe1Year || '—'}</div>
                </div>
                <div className="pe-card">
                  <div className="pe-period">3 Year</div>
                  <div className="pe-value">{stockData.medianPe3Year || '—'}</div>
                </div>
                <div className="pe-card">
                  <div className="pe-period">5 Year</div>
                  <div className="pe-value">{stockData.medianPe5Year || '—'}</div>
                </div>
              </div>
            </div>

            {/* Concall placeholder */}
            <div className="section">
              <div className="section-title">Concall Analysis</div>
              <div className="table-wrap" style={{ padding: '32px', textAlign: 'center' }}>
                <div style={{ fontSize: '28px', marginBottom: '12px' }}>🎙</div>
                <div style={{ color: '#6b7280', fontSize: '14px', marginBottom: '8px' }}>
                  AI-powered concall analysis coming soon
                </div>
                <div style={{ color: '#374151', fontSize: '12px' }}>
                  Will include: Growth plans · Capex · JV · Key Q&A from latest concall
                </div>
              </div>
            </div>

            <div className="footer-note">
              Data sourced from screener.in · For research purposes only · Not investment advice
            </div>
          </>
        )}
      </div>
    </>
  );
}
